import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, ProjectContext } from "../../base.ts";

/**
 * ☁️ Dr. Cloud — PhD in Cloud Native & IAM Integrity (TypeScript)
 * Generated by Sovereign Forge.
 */
export class CloudPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "cloud";
        this.name = "Cloud";
        this.emoji = "☁️";
        this.role = "PhD Cloud Architect";
        this.phd_identity = "Cloud Native & IAM Integrity (TypeScript)";
        this.stack = "Bun";
        this.healingPrompt = "";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js"],
            rules: [
          {
                    "regex": "Resource:\\s*['\"]\\*['\"]",
                    "issue": "IAM: Permissão excessiva (Wildcard Resource) detectada em política Cloud. Aplique o princípio de menor privilégio.",
                    "severity": "critical"
          },
          {
                    "regex": "MemorySize:\\s*[1-9][0-9]{3}",
                    "issue": "Cost: Função Lambda com alocação de memória alta. Verifique se é realmente necessário PhD.",
                    "severity": "low"
          },
          {
                    "regex": "publicReadAccess:\\s*true",
                    "issue": "Security: Acesso público ao recurso cloud detectado. Risco de vazamento de dados.",
                    "severity": "high"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Cloud operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Cloud, PhD em Cloud Native & IAM Integrity (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
